('old-data-berta2-all-20260501-01', 'f9262f00', 'max_capacity', '4', 'Berta 2.0', U&'{"id":"f9262f00","Nom commercial":"Ti''Jean","Raison sociale":"","Motif Hors ligne":"","En ligne":"oui","Zone":"sud","Nom de la commune":"Saint-Joseph","Adresse":"128 Route de Jean Petit, 97480 Saint-Joseph - Jean Petit","Site web":"https://www.abacard.net/fr/page/abacard-home-a-la-reunion","Groupe cat\00E9gorie":"H\00E9bergement","Nom cat\00E9gorie":"Location saisonni\00E8re","Nom sous cat\00E9gorie":"Maison","Localisations":"Milieu rural","Code postal":"97480","Bureau postal":"Saint-Joseph","Lieux-dits":"Jean Petit","Prestations sur place":"chauffage , jardin , parking , wifi , climatisation , Cafeti\00E8re , cuisine \00E9quip\00E9e , barbecue , four , micro-ondes , TV , Lit parapluie sur demande , fer et planche \00E0 repasser , piscine , ventilateur , linge de maison , lave vaisselle , terrasse , salon de jardin , plaque de cuisson , s\00E8che-cheveux , bouilloire , grille-pain , dressing , salle de bain priv\00E9e , armoire , \00E9quipement b\00E9b\00E9 , lave-linge , sur r\00E9servation","Prestations \00E0 proximit\00E9":"sentier de randonn\00E9e,sites touristiques,centre ville","Mode de paiement":"Esp\00E8ces,Virement","Langues":"fran\00E7ais,cr\00E9ole","Fixe":"","Mobile":"","Autre t\00E9l\00E9phone":"","Fax":"","E-Mail":"abacardhome@gmail.com","Capacit\00E9":"4","Classement":"4 Etoile(s)","Accroche":"Venez d\00E9couvrir le Sud Sauvage et d\00E9tendez-vous dans ce logement calme et \00E9l\00E9gant, d\00E9cor\00E9 avec go\00FBt.","Descriptif":"Logement de plein pied comprenant 2 chambres, s\00E9jour, salon, cuisine \00E9quip\00E9e, varangue, jardin. Stationnement privatif\\n\\n\\"Ti''Jean\\" a ouvert ses portes en novembre 2023.\\n\\n\\n\\n\\nLe logement:\\n\\n\+01F6CE Un portail permettant l''acc\00E8s au logement, stationnement possible dans l''all\00E9e.\\n\\nExt\00E9rieur compos\00E9 d''un jardin \00E0 l''avant et \00E0 l''arri\00E8re de la maison permettant une double exposition (coucher de soleil!)\\n\\nAcc\00E8s depuis la varangue, vous entrerez dans la salle \00E0 manger et la cuisine enti\00E8rement \00E9quip\00E9e (four, micro ondes, r\00E9frig\00E9rateur, vaisselles, marmite \00E0 riz, cafeti\00E8re, bouilloire, ...), qui dessert le salon \00E9quip\00E9 d''un canap\00E9 et d''une TV \00E9cran plat.\\n\\nCoup de c\0153ur assur\00E9 !!!\\n\\nDe cet espace, un couloir permettant d''acc\00E9der \00E0 :\\n\\n* une premi\00E8re chambre avec un lit 160 x 200 cm compl\00E9t\00E9 d''un dressing\\n\\n* une seconde chambre avec un lit 160 x 200 cm compl\00E9t\00E9 d''un dressing\\n\\n* une salle d''eau avec double vasque, douche \00E0 l''italienne, lave-linge.\\n\\nLes serviettes de toilettes sont fournis.\\n\\n* un WC s\00E9par\00E9.\\n\\nDepuis mars 2024 : une piscine hors sol permettant de se rafraichir accompagn\00E9e d''une douche ext\00E9rieu","Descriptif du plan d''acc\00E8s":"Jean Petit","Jours et horaires d''ouverture":"","Labels":"","Date de cr\00E9ation - Etablissement":"8/1/2024","Date de fermeture":"","Fournisseur - Nom":"Mr David GABORIT","Fournisseur - SIRET":"53271013400034","Fournisseur - adresse":"Mr David GABORIT: 37 Chemin du Roc de Peillet, 30150 Roquemaure","Fournisseur - contacts":"abacardhome@gmail.com / 06 68 28 56 54","Fournisseur - date de cr\00E9ation":"","Fournisseur - Code postal":"","Fournisseur - Bureau":"","Fournisseur - Code NAF":"","Fournisseur - Chambre consulaire":"","Fournisseur - Forme juridique":"","Fournisseur - CFE":"","Nb Produits":"","Coordonn\00E9es GPS":"-21.359846, 55.631012","Liste URL moteur":"","Tarif Montant":"","Tarif libell\00E9":"","Num taxe de s\00E9jour":"CSC623HTK","Descriptif OTI":"","Accroche OTI":"","Status":"","commentaire":"","Date de derniere modification":"","Colones modifi\00E9es":"","Aire d''adh\00E9sion":"","source_system":"berta_v2_csv_export"}', 'pending', 'true'),
